    inputHtmlFilePath = SanitizeInput(inputHtmlFilePath);
    outputPdfFilePath = SanitizeInput(outputPdfFilePath);

    // Build the wkhtmltopdf command
    string command = $"wkhtmltopdf {options.PageSize} {options.Orientation} {inputHtmlFilePath} {outputPdfFilePath}";

    // Start the process to execute the command
    ProcessStartInfo startInfo = new ProcessStartInfo("cmd", "/c " + command);
    startInfo.UseShellExecute = false;
    startInfo.RedirectStandardOutput = true;
    startInfo.CreateNoWindow = true;

